usage_examples.code:
// 使用 TP 生成固定宽度的脉冲
VAR
    TriggerSignal: BOOL;
    PulseTimer: TP;
    OutputPulse: BOOL;
END_VAR

PulseTimer(IN:=TriggerSignal, PT:=T#1s);
OutputPulse := PulseTimer.Q;

// 使用 TP 控制脉冲宽度
VAR
    StartPulse: BOOL;
    PulseTimer: TP;
    ValveControl: BOOL;
    PulseWidth: TIME := T#200ms;
END_VAR

PulseTimer(IN:=StartPulse, PT:=PulseWidth);
ValveControl := PulseTimer.Q;

// 使用 TP 控制脉冲序列
VAR
    StartSequence: BOOL;
    Timer1: TP;
    Timer2: TP;
    Timer3: TP;
    Step1: BOOL;
    Step2: BOOL;
    Step3: BOOL;
END_VAR

// 第一步：1秒脉冲
Timer1(IN:=StartSequence, PT:=T#1s);
Step1 := Timer1.Q;

// 第二步：2秒脉冲（在第一步结束后开始）
Timer2(IN:=NOT Timer1.Q AND StartSequence, PT:=T#2s);
Step2 := Timer2.Q;

// 第三步：1.5秒脉冲（在第二步结束后开始）
Timer3(IN:=(NOT Timer1.Q) AND (NOT Timer2.Q) AND StartSequence, PT:=T#1s500ms);
Step3 := Timer3.Q;
